           DIGITALBANK - Styles CSS
           âââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ */

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        :root {
            --primary: #0a2540;
            --primary-light: #1a3a5c;
            --accent: #00d4aa;
            --accent-hover: #00b894;
            --danger: #ff6b6b;
            --danger-hover: #ee5a5a;
            --warning: #ffd93d;
            --success: #00d4aa;
            --bg-dark: #0a0e14;
            --bg-card: #111820;
            --bg-input: #1a2332;
            --text-primary: #ffffff;
            --text-secondary: #8b9cb3;
            --text-muted: #5a6a7e;
            --border: #2a3a4e;
            --shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
            --shadow-accent: 0 4px 20px rgba(0, 212, 170, 0.2);
            --radius: 12px;
            --radius-lg: 20px;
        }

        body {
            font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, sans-serif;
            background: var(--bg-dark);
            color: var(--text-primary);
            min-height: 100vh;
            line-height: 1.6;
        }

        .app-container {
            min-height: 100vh;
            display: flex;
            flex-direction: column;
        }

        .hidden {
            display: none !important;
        }

        /* Test Mode Banner */
        .test-mode-banner {
            background: linear-gradient(90deg, var(--warning) 0%, #ff9f43 100%);
            color: var(--primary);
            padding: 8px 16px;
            text-align: center;
            font-weight: 600;
            font-size: 0.85rem;
        }

        /* Header */
        .header {
            background: linear-gradient(135deg, var(--primary) 0%, var(--primary-light) 100%);
            padding: 16px 24px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 1px solid var(--border);
            position: sticky;
            top: 0;
            z-index: 100;
        }

        .logo {
            display: flex;
            align-items: center;
            gap: 12px;
            font-size: 1.5rem;
            font-weight: 700;
            color: var(--text-primary);
        }

        .logo-icon {
            width: 40px;
            height: 40px;
            background: var(--accent);
            border-radius: 10px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            color: var(--primary);
            font-size: 1rem;
        }

        .logo-icon.large {
            width: 64px;
            height: 64px;
            font-size: 1.5rem;
            margin: 0 auto 16px;
        }

        .user-menu {
            display: flex;
            align-items: center;
            gap: 16px;
        }

        .user-name {
            color: var(--text-secondary);
            font-size: 0.9rem;
        }

        /* Navigation */
        .nav-tabs {
            background: var(--bg-card);
            padding: 0 24px;
            display: flex;
            gap: 4px;
            border-bottom: 1px solid var(--border);
            overflow-x: auto;
        }

        .nav-tab {
            padding: 16px 24px;
            background: transparent;
            border: none;
            color: var(--text-secondary);
            font-size: 0.95rem;
            font-weight: 500;
            cursor: pointer;
            position: relative;
            transition: all 0.2s ease;
            white-space: nowrap;
            font-family: inherit;
        }

        .nav-tab:hover {
            color: var(--text-primary);
        }

        .nav-tab.active {
            color: var(--accent);
        }

        .nav-tab.active::after {
            content: '';
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 3px;
            background: var(--accent);
            border-radius: 3px 3px 0 0;
        }

        /* Main Content */
        .main-content {
            flex: 1;
            padding: 24px;
            max-width: 1200px;
            margin: 0 auto;
            width: 100%;
        }

        /* Cards */
        .card {
            background: var(--bg-card);
            border-radius: var(--radius-lg);
            padding: 24px;
            margin-bottom: 24px;
            border: 1px solid var(--border);
            box-shadow: var(--shadow);
        }

        .card-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
        }

        .card-title {
            font-size: 1.25rem;
            font-weight: 600;
            color: var(--text-primary);
        }

        /* Balance Display */
        .balance-cards {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
            gap: 20px;
            margin-bottom: 24px;
        }

        .balance-card {
            background: linear-gradient(135deg, var(--primary) 0%, var(--primary-light) 100%);
            border-radius: var(--radius-lg);
            padding: 24px;
            position: relative;
            overflow: hidden;
            cursor: pointer;
            border: 2px solid transparent;
            transition: all 0.2s ease;
        }

        .balance-card:hover {
            transform: translateY(-2px);
        }

        .balance-card.selected {
            border-color: var(--accent);
        }

        .balance-card::before {
            content: '';
            position: absolute;
            top: -50%;
            right: -50%;
            width: 100%;
            height: 100%;
            background: radial-gradient(circle, rgba(0, 212, 170, 0.1) 0%, transparent 70%);
        }

        .balance-card-type {
            font-size: 0.9rem;
            color: var(--text-secondary);
            margin-bottom: 4px;
        }

        .balance-card-number {
            font-family: 'JetBrains Mono', monospace;
            font-size: 0.8rem;
            color: var(--text-muted);
            margin-bottom: 16px;
        }

        .balance-amount {
            font-size: 2rem;
            font-weight: 700;
            color: var(--text-primary);
        }

        .balance-currency {
            font-size: 1rem;
            color: var(--text-secondary);
            margin-left: 4px;
        }

        /* Transactions */
        .transaction-list {
            display: flex;
            flex-direction: column;
            gap: 12px;
        }

        .transaction-item {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 16px;
            background: var(--bg-input);
            border-radius: var(--radius);
            transition: all 0.2s ease;
        }

        .transaction-item:hover {
            background: var(--primary-light);
        }

        .transaction-info {
            display: flex;
            flex-direction: column;
            gap: 4px;
        }

        .transaction-description {
            font-weight: 500;
            color: var(--text-primary);
        }

        .transaction-date {
            font-size: 0.85rem;
            color: var(--text-muted);
        }

        .transaction-amount {
            font-family: 'JetBrains Mono', monospace;
            font-weight: 600;
            font-size: 1rem;
        }

        .transaction-amount.credit {
            color: var(--success);
        }

        .transaction-amount.debit {
            color: var(--danger);
        }

        /* Forms */
        .form-group {
            margin-bottom: 20px;
        }

        .form-label {
            display: block;
            margin-bottom: 8px;
            font-weight: 500;
            color: var(--text-secondary);
            font-size: 0.9rem;
        }

        .form-input, .form-select {
            width: 100%;
            padding: 14px 16px;
            background: var(--bg-input);
            border: 1px solid var(--border);
            border-radius: var(--radius);
            color: var(--text-primary);
            font-size: 1rem;
            font-family: inherit;
            transition: all 0.2s ease;
        }

        .form-input:focus, .form-select:focus {
            outline: none;
            border-color: var(--accent);
            box-shadow: 0 0 0 3px rgba(0, 212, 170, 0.1);
        }

        .form-input::placeholder {
            color: var(--text-muted);
        }

